        <div className="relative max-w-screen-2xl mx-auto px-6 lg:px-12 w-full z-10">
            <div className="max-w-3xl">
                <div className="inline-flex items-center gap-2 bg-masuma-orange/20 border border-masuma-orange text-masuma-orange px-4 py-1.5 mb-6 backdrop-blur-md">
                    <span className="w-2 h-2 bg-masuma-orange rounded-full animate-pulse"></span>
                    <span className="text-xs font-bold uppercase tracking-[0.2em] text-white">Official Distributor • East Africa</span>
                </div>
                <h1 className="text-5xl md:text-7xl lg:text-8xl font-bold font-display uppercase leading-[0.9] mb-8 tracking-tighter">
                    Built for the <br/>
                    <span className="text-transparent bg-clip-text bg-gradient-to-r from-masuma-orange to-orange-500">Long Road.</span>
                </h1>
                <p className="text-gray-300 text-lg md:text-xl font-light leading-relaxed max-w-2xl mb-10 border-l-4 border-masuma-orange pl-6">
                    Masuma Autoparts East Africa is the bridge between Japanese precision engineering and the rugged demands of the African continent. We provide reliability where it matters most.
                </p>
                <div className="flex flex-col sm:flex-row gap-4">
                    <button 
                        onClick={() => setView('CATALOG')}
                        className="bg-white text-masuma-dark hover:bg-masuma-orange hover:text-white px-8 py-4 font-bold uppercase tracking-widest text-xs md:text-sm transition duration-300 shadow-xl flex items-center justify-center gap-2"
                    >
                        Explore Our Catalog <ArrowRight size={16} />
                    </button>
                    <button 
                        onClick={() => setView('CONTACT')}
                        className="border-2 border-white/20 text-white hover:bg-white hover:text-masuma-dark px-8 py-4 font-bold uppercase tracking-widest text-xs md:text-sm transition duration-300 backdrop-blur-sm"
                    >
                        Visit Showroom
                    </button>
                </div>
            </div>
        </div>
      </div>

      {/* 2. THE MASUMA STORY / CONTEXT */}
      <section className="py-24 bg-white">
          <div className="max-w-screen-2xl mx-auto px-6 lg:px-12">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-20 items-center">
                  <div>
                      <h2 className="text-4xl font-bold text-masuma-dark font-display uppercase mb-6 leading-none">
                          The Challenge of <br/>
                          <span className="text-gray-400">Kenyan Roads</span>
                      </h2>
                      <div className="space-y-6 text-gray-600 text-lg leading-relaxed">
                          <p>
                              Japan and Kenya have very different driving environments. In Tokyo, roads are smooth and traffic is regulated. In Nairobi, a vehicle faces potholes, speed bumps, dust, and heavy traffic jams daily.
                          </p>
                          <p>
                              <strong>Standard aftermarket parts aren't built for this.</strong> They fail prematurely because they use soft rubber bushings designed for smooth highways, or standard filtration media that clogs quickly in dusty terrain.
                          </p>
                          <p className="text-masuma-dark font-bold border-l-4 border-masuma-orange pl-6 py-2 bg-gray-50">
                              Masuma East Africa recognized this gap. We work directly with the Masuma engineering team to supply "Tropical Spec" components reinforced for heat, dust, and vibration.
                          </p>
                      </div>
                  </div>
                  <div className="relative">
                      <div className="absolute -inset-4 border-2 border-masuma-orange translate-x-4 translate-y-4 hidden md:block"></div>
                      <img src="https://images.unsplash.com/photo-1486006920555-c77dcf18193c?auto=format&fit=crop&w=800&q=80" alt="Engine Bay" className="w-full h-[400px] object-cover shadow-2xl relative z-10 grayscale hover:grayscale-0 transition duration-700" />
                  </div>
              </div>
          </div>
      </section>

      {/* 3. CORE PILLARS (Dark Section) */}
      <section className="py-24 bg-masuma-dark text-white relative overflow-hidden">
          <div className="absolute top-0 right-0 w-2/3 h-full bg-[#222] skew-x-12 transform translate-x-1/4 opacity-50"></div>

          <div className="max-w-screen-2xl mx-auto px-6 lg:px-12 relative z-10">
              <div className="text-center max-w-3xl mx-auto mb-20">
                  <span className="text-masuma-orange font-bold uppercase tracking-widest text-xs">Our Philosophy</span>
                  <h2 className="text-4xl md:text-5xl font-bold font-display uppercase mt-2">Why Masuma?</h2>
                  <div className="w-20 h-1 bg-masuma-orange mx-auto mt-6"></div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  {[
                      {
                          icon: Globe,
                          title: "Japanese Engineering",
                          desc: "Designed in Tokyo. Every part adheres strictly to OEM geometric specifications, ensuring a perfect fit every time. No modifications needed."
                      },
                      {
                          icon: ShieldCheck,
                          title: "12-Month Warranty",
                          desc: "We stand behind our quality. If a part fails due to a manufacturing defect within 12 months, we replace it. No questions asked."
                      },
                      {
                          icon: Wrench,
                          title: "Mechanic Approved",
                          desc: "Trusted by over 500 garages in Nairobi. Mechanics prefer Masuma because they don't bounce back for warranty claims."
                      }
                  ].map((item, idx) => (
                      <div key={idx} className="bg-white/5 p-10 border border-white/10 hover:border-masuma-orange hover:bg-white/10 transition duration-500 group">
                          <div className="w-16 h-16 bg-masuma-orange/10 rounded-full flex items-center justify-center mb-6 group-hover:bg-masuma-orange transition-colors">
                              <item.icon size={32} className="text-masuma-orange group-hover:text-white transition-colors" />
                          </div>
                          <h3 className="text-xl font-bold font-display uppercase mb-4 tracking-wide">{item.title}</h3>
                          <p className="text-gray-400 leading-relaxed text-sm">
                              {item.desc}
                          </p>
                      </div>
                  ))}
              </div>
          </div>
      </section>

      {/* 4. PRODUCT CATEGORY DEEP DIVE */}
      <section className="py-24 bg-gray-50">
          <div className="max-w-screen-2xl mx-auto px-6 lg:px-12">
              <div className="flex flex-col md:flex-row justify-between items-end mb-16">
                  <div>
                      <span className="text-masuma-orange font-bold uppercase tracking-widest text-xs">Product Focus</span>
                      <h2 className="text-4xl font-bold text-masuma-dark font-display uppercase mt-2">Engineered to Outlast</h2>
                  </div>
                  <button onClick={() => setView('CATALOG')} className="hidden md:flex items-center gap-2 text-masuma-dark font-bold uppercase text-xs tracking-widest hover:text-masuma-orange transition border-b-2 border-masuma-dark hover:border-masuma-orange pb-1">
                      View Full Catalog <Activity size={16} />
                  </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {/* Suspension */}
                  <div className="bg-white p-8 shadow-sm border-t-4 border-masuma-orange hover:shadow-xl transition group h-full flex flex-col">
                      <h3 className="text-2xl font-bold font-display text-masuma-dark mb-4">Suspension</h3>
                      <p className="text-gray-600 text-sm mb-6 leading-relaxed flex-1">
                          Our bushings use a high-density rubber compound that resists cracking under heavy vibration. Ball joints feature mirror-polished studs and high-performance grease to reduce friction and wear on rough roads.
                      </p>
                      <ul className="space-y-3 mt-auto">
                          <li className="flex items-center gap-3 text-xs font-bold text-gray-700 uppercase"><CheckCircle size={16} className="text-masuma-orange"/> Reinforced Rubber</li>
                          <li className="flex items-center gap-3 text-xs font-bold text-gray-700 uppercase"><CheckCircle size={16} className="text-masuma-orange"/> Dust-Sealed Joints</li>
                      </ul>
                  </div>

                  {/* Brakes */}
                  <div className="bg-white p-8 shadow-sm border-t-4 border-masuma-dark hover:shadow-xl transition group h-full flex flex-col">
                      <h3 className="text-2xl font-bold font-display text-masuma-dark mb-4">Braking Systems</h3>
                      <p className="text-gray-600 text-sm mb-6 leading-relaxed flex-1">
                          Masuma ceramic brake pads are formulated to handle high heat without fading. They produce minimal dust and include anti-squeal shims, providing quiet, confident stopping power in Nairobi traffic.
                      </p>
                      <ul className="space-y-3 mt-auto">
                          <li className="flex items-center gap-3 text-xs font-bold text-gray-700 uppercase"><CheckCircle size={16} className="text-masuma-dark"/> Low Dust Ceramic</li>
                          <li className="flex items-center gap-3 text-xs font-bold text-gray-700 uppercase"><CheckCircle size={16} className="text-masuma-dark"/> High Temp Resistance</li>
                      </ul>
                  </div>

                  {/* Filtration */}
                  <div className="bg-white p-8 shadow-sm border-t-4 border-gray-400 hover:shadow-xl transition group h-full flex flex-col">
                      <h3 className="text-2xl font-bold font-display text-masuma-dark mb-4">Filtration</h3>
                      <p className="text-gray-600 text-sm mb-6 leading-relaxed flex-1">
                          Protect your engine from dust and bad fuel. Our filters use multi-layer media that traps 99% of contaminants while maintaining high flow rates, essential for preserving engine life in dusty environments.
                      </p>
                      <ul className="space-y-3 mt-auto">
                          <li className="flex items-center gap-3 text-xs font-bold text-gray-700 uppercase"><CheckCircle size={16} className="text-gray-400"/> Multi-layer Media</li>
                          <li className="flex items-center gap-3 text-xs font-bold text-gray-700 uppercase"><CheckCircle size={16} className="text-gray-400"/> High Pressure Valve</li>
                      </ul>
                  </div>
              </div>
          </div>
      </section>

      {/* 5. COUNTERFEIT WARNING */}
      <section className="py-24 bg-white border-y border-gray-100">
          <div className="max-w-5xl mx-auto px-6">
              <div className="bg-red-50 rounded-2xl p-8 md:p-12 flex flex-col md:flex-row items-start gap-10 border border-red-100">
                  <div className="md:w-1/3">
                      <div className="inline-flex items-center justify-center p-4 bg-white rounded-full text-red-600 mb-6 shadow-sm">
                          <AlertTriangle size={32} />
                      </div>
                      <h2 className="text-3xl font-bold text-masuma-dark font-display uppercase mb-4 leading-none">Beware of <br/>Counterfeits</h2>
                      <p className="text-red-800 font-bold text-sm">Protect your vehicle from fake parts.</p>
                  </div>

                  <div className="md:w-2/3 space-y-6">
                      <p className="text-gray-700 leading-relaxed">
                          The Kenyan market is flooded with fake parts packaged to look like originals. These parts often use inferior materials that can lead to catastrophic engine failure or accidents.
                      </p>

                      <div className="bg-white p-6 rounded-lg border border-red-100 shadow-sm">
                          <h4 className="font-bold text-masuma-dark uppercase text-sm mb-4 border-b border-gray-100 pb-2">How to Spot Genuine Masuma:</h4>
                          <ul className="space-y-4">
                              <li className="flex items-start gap-3">
                                  <Star size={18} className="text-masuma-orange mt-0.5 shrink-0" />
                                  <span className="text-sm text-gray-600"><strong>Hologram Seal:</strong> Every genuine box features a holographic security seal that changes color when tilted.</span>
                              </li>
                              <li className="flex items-start gap-3">
                                  <Star size={18} className="text-masuma-orange mt-0.5 shrink-0" />
                                  <span className="text-sm text-gray-600"><strong>Batch Number:</strong> Printed directly on the part (e.g., filter canister or brake backing plate), not just on a sticker.</span>
                              </li>
                              <li className="flex items-start gap-3">
                                  <Star size={18} className="text-masuma-orange mt-0.5 shrink-0" />
                                  <span className="text-sm text-gray-600"><strong>Authorized Source:</strong> Buy only from Masuma Autoparts East Africa Limited or our verified partners listed on this website.</span>
                              </li>
                          </ul>
                      </div>
                  </div>
              </div>
          </div>
      </section>

      {/* 6. STATS */}
      <div className="bg-masuma-dark py-20 border-t border-gray-800">
          <div className="max-w-7xl mx-auto px-6 grid grid-cols-2 md:grid-cols-4 gap-12 text-center text-white">
              {[
                  { label: "Product Categories", value: "45+" },
                  { label: "Fitment Accuracy", value: "99.9%" },
                  { label: "Partner Garages", value: "500+" },
                  { label: "Years in Market", value: "20+" },
              ].map((stat, idx) => (
                  <div key={idx} className="p-4 border border-white/5 bg-white/5 hover:bg-masuma-orange hover:border-masuma-orange transition duration-500 rounded-lg group">
                      <div className="text-4xl md:text-5xl font-bold font-display text-masuma-orange mb-2 group-hover:text-white transition">{stat.value}</div>
                      <div className="text-[10px] uppercase tracking-[0.2em] text-gray-400 font-bold group-hover:text-white/80 transition">{stat.label}</div>
                  </div>
              ))}
          </div>
      </div>
    </div>
  );
};

export default About;
